const helpers = this.helpers;
const input = $input.first().json;
const method = input.unsubscribe_method;
const url = input.unsubscribe_url;
const mailto = input.unsubscribe_mailto;

let status = 'nicht erfolgreich';
let reason = '';

if (method === 'one-click' && url) {
  // RFC 8058 one-click unsubscribe via HTTP POST
  try {
    const response = await helpers.httpRequest({
      method: 'POST',
      url: url,
      headers: {
        'List-Unsubscribe': 'One-Click',
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: 'List-Unsubscribe=One-Click',
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
      timeout: 15000
    });

    const statusCode = response.statusCode || response.status || 0;
    if (statusCode >= 200 && statusCode < 400) {
      status = 'erfolgreich';
      reason = 'One-click unsubscribe executed successfully (HTTP ' + statusCode + ')';
    } else {
      reason = 'HTTP ' + statusCode + ': Unsubscribe request rejected by server';
    }
  } catch (err) {
    reason = 'Request failed: ' + (err.message || 'Unknown error');
  }

} else if (method === 'mailto' && mailto) {
  // Send unsubscribe email via SMTP
  try {
    await helpers.httpRequest({
      method: 'POST',
      url: 'https://siteware-email-dashboard.vercel.app/api/email/audit',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        email_id: input.email_id,
        action: 'unsubscribe_mailto_flagged',
        mailto: mailto,
        note: 'Mailto unsubscribe requires manual action or SMTP node',
        timestamp: new Date().toISOString()
      }),
      json: false
    });
    status = 'nicht erfolgreich';
    reason = 'Mailto-Abmeldung markiert für manuelle Bearbeitung. Adresse: ' + mailto;
  } catch (err) {
    reason = 'Mailto-Abmeldung: Adresse ' + mailto + ' (Audit-Log fehlgeschlagen: ' + err.message + ')';
  }

} else {
  reason = 'Kein Abmeldelink in den E-Mail-Headern gefunden';
}

return [{ json: {
  email_id: input.email_id,
  sender: input.sender,
  unsubscribe_method: method || 'not-found',
  status: status,
  reason: reason,
  timestamp: new Date().toISOString()
}}];

