// UTF-8 repair: fixes quoted-printable latin-1 mis-decoded strings (e.g. fÃ¼r → für)
function fixEncoding(str) {
  if (!str || typeof str !== 'string') return str || '';
  try { return decodeURIComponent(escape(str)); } catch (e) { return str; }
}

// --- SENDER ---
let fromAddress = '';
let fromName = '';
if (typeof data.from === 'string') {
  const match = data.from.match(/^(.*?)\s*<([\w.+-]+@[\w.-]+\.\w+)>\s*$/);
  if (match) {
    fromName = match[1].trim().replace(/^"|"$/g, '');
    fromAddress = match[2];
  } else {
    fromAddress = data.from.match(/[\w.+-]+@[\w.-]+\.\w+/)?.[0] || '';
    fromName = fromAddress;
  }
} else if (data.from?.value?.[0]) {
  fromAddress = data.from.value[0].address || '';
  fromName = data.from.value[0].name || fromAddress;
} else if (data.from?.text) {
  const match = data.from.text.match(/^(.*?)\s*<([\w.+-]+@[\w.-]+\.\w+)>/);
  if (match) { fromName = match[1].trim(); fromAddress = match[2]; }
}

// Fallback to sender_email / sender_name if from parsing failed
if (!fromAddress) fromAddress = data.sender_email || '';
if (!fromName) fromName = data.sender_name || fromAddress;

fromName = fromName || fromAddress;
const senderDomain = fromAddress.includes('@') ? fromAddress.split('@')[1].toLowerCase() : 'unknown';

