  const urlMatch = listUnsub.match(/<(https?:\/\/[^>]+)>/);
  const mailtoMatch = listUnsub.match(/<mailto:([^>]+)>/);
  if (urlMatch) listUnsubscribeUrl = urlMatch[1];
